(function () {
  const meta = {
    name: 'BackupReminder',
    version: '1.0.0',
    platform: '0.26.0',
    description: 'Periodic notification reminding the user to back up.',
  };

  return {
    meta,
    init() {
      // Friendly reminder to backup!
      let secs = parseInt(tw.call('getJSONObject', '$GeneralSettings')?.backup?.backupInSeconds || 1800, 10);
      setInterval(() => {
        tw.ui.notify('Remember to backup', 'I');
      }, secs * 1000);
    },
  };
})();

/**
 * ## Description
 * Registers a command palette command (Ctrl/Cmd+K) that closes every open
 * note except the *active* one — the note you last opened / navigated to.
 *
 * Finding the active note:
 *   - We subscribe to `tiddler.show` (the event fired whenever a note is opened
 *     or re-shown) and remember its title on `tw.tmp.activeNote`. This beats the
 *     "last in tw.tiddlers.visible" heuristic, which misses re-showing a note
 *     that is already open (showTiddler doesn't reorder the visible list).
 *   - Tabs layout: `tw.tabs.active` (the selected tab) takes precedence.
 *   - Fallback: the most recently opened note (last in `tw.tiddlers.visible`).
 */
(function () {
  const meta = {
    name: 'CloseOthers',
    version: '1.0.0',
    platform: '0.26.0',
    description: 'Command palette action to close every open note except the active one.',
  };

  function recordActiveNote(title) {
    if (typeof title === 'string') tw.tmp.activeNote = title;
  }

  function activeNote() {
    let open = tw.tiddlers.visible;
    let active = (tw.tabs && tw.tabs.active) || tw.tmp.activeNote;
    if (active && open.includes(active)) return active;
    return open[open.length - 1] || null; // fallback: most recently opened
  }

  function closeAllButActive() {
    let open = tw.tiddlers.visible;
    if (open.length <= 1) return tw.ui.notify('Nothing to close', 'I');
    let keep = activeNote();
    // filter() snapshots before we close — tw.tiddlers.visible mutates as each closes.
    open.filter(title => title !== keep).forEach(title => tw.events.send('tiddler.close', title));
    // Re-show the kept note: it's already open, so showTiddler early-returns into
    // scrollToTiddler() (and refocuses its tab in tabs mode).
    if (keep) tw.events.send('tiddler.show', keep);
    tw.ui.notify(`Closed ${open.length - 1} note(s), kept '${keep}'`, 'D');
  }

  return {
    meta,
    init() {
      tw.tmp = tw.tmp || {};

      // Remember the most recently shown note. Deduped across soft reloads by the
      // handler name; the title lives on tw.tmp (not this closure) so a re-eval keeps
      // reading the value the live handler writes.
      tw.events.subscribe('tiddler.show', recordActiveNote);

      tw.extensions.registerCommand({
        label: 'Close all but active note',
        run: closeAllButActive, // TODO: This should be pub/sub: event: 'tiddlers.closeAllButActive'
      });
    },
  };
})();

tw.extensions.registerMacro(
  'marc',
  'loadThemeButton',
  (filter, force = true) => {
    if (!filter) filter = 'default';
    return tw.ui.button(`Load Theme: ${filter}`, 'package.reload.url', {url: './packages/themes.json', name: 'test', filter, force});
  },
  {
    description: 'Reload the themes package from ./packages/themes.json with an optional filter.',
    example: '<<marc.loadThemeButton default>>',
  },
);
tw.events.subscribe('script.loaded', (name) => {
  if (name !== 'highlight-core') return;
  tw.core.dom.addScript('highlight-lang-powershell', '//cdnjs.cloudflare.com/ajax/libs/highlight.js/11.9.0/languages/powershell.min.js');
}, 'marc.addLanguages');

tw.tiddlers.all.filter(t => t.type === 'x-twiki').forEach(t => (t.type = 'x-twikki'));

// We need a <<button name:"Delete Something" msg:"tiddlers.delet" params:"tag:Marc">>

// Some Snippets
if (0) {
  // Find duplicate tiddlers
  tw.tiddlers.all.filter(td => tw.tiddlers.all.filter(t => t.title === td.title).length > 1).map(t => t.title);

  // Delete duplicate tiddlers
  tw.tiddlers.all.filter(td => tw.tiddlers.all.filter(t => t.title === td.title).length > 1).map(t => t.title).forEach(t => (tw.run.deleteTiddler(t, true)));

  // Delete tiddlers from a package
  tw.tiddlers.all.filter(t => t.package === 'base').map(t => t.title).forEach(t => (tw.run.deleteTiddler(t, true)));

}
